INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028542e3c98b0941766187', '非常幸运这次能够入住花园酒店，酒店的各方面都给我留下了特别美好的印象。不管是环境还是服务，有其是餐饮，都是一流的。酒店大堂金碧辉煌，花园美轮美奂，各处鲜花环绕，细节都非常完美。太喜欢了！下次来广州一定选择再次入住。', '["https://dimg04.c-ctrip.com/images/0201n12000ccsi6bj905A_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235f12000ccscv5l7647_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000ccsfrin8247_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000ccsgjc8EB68_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉大床套房', '套房', '家庭亲子', 107, 0, 6, 8, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68028542e3c98b0941766188', '这次出行广州入住了老花园酒店，酒店服务、美食、园林布局果然名不虚传，很有老牌白金五星酒店的风范，较有底蕴。出行前每次致电酒店都有宾至如归的感觉，check in入住当天Viria的专业态度和贴心服务更是留下了深刻印象；瀑布餐厅的景观、荔湾艇的晚餐、行政走廊的早餐都不妨一试。', '["https://dimg04.c-ctrip.com/images/0235e12000ccy2ltx7E33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000ccyagow6D4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000ccy8x2cA2B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000ccy873427DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000ccy2lu10670_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '花园大床房', '大床房', '朋友出游', 137, 0, 6, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68028542e3c98b0941766189', '非常棒的体验～完全没得挑
从办理入住到离开每天都是开心的～', '["https://dimg04.c-ctrip.com/images/0231z12000d4vj6f7EAFC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000d4w5l8s622C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-05', '红棉大床套房', '套房', '家庭亲子', 29, 0, 13, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b094176618a', '房间蛮新的，重新装修，不是想象中很老的破五星，大堂特别气派，关键酒店里吃货的天堂，二楼荔湾亭早茶及中晚餐味道很好，三楼桃园馆是米其林餐厅，做的色香味俱全，很细腻，味道很好！一定要品尝，吃了对面广州酒家后觉得还是酒店里好吃！连住三晚！', '["https://dimg04.c-ctrip.com/images/0231y12000cc5dst20A76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000cc5fo616389_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000cc5bnzh1749_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000cc5a3cp7517_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000cc5fzlf1E4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000cc5bqkm1AD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000cc5ckr8CD31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000cc5g3n5692C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000cc5ethg82F3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 116, 0, 44, 9, '["餐饮设施","房间设施","整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度'),
('68028542e3c98b094176618b', '感谢酒店再一次给我们升级到粤韵房。感谢！酒店各方面都很棒！很美好的入住体验。今后还会选择，期待下次还能有美好的经历！谢谢！', '["https://dimg04.c-ctrip.com/images/0230f12000cnp8n7n1D08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000cnp82cqA119_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000cnp8gdy704C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y12000cnp71099458_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-30', '红棉双床套房', '套房', '其他', 61, 0, 8, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b094176618c', '酒店住的特别舒服 早餐丰富 下次来还住这里', '["https://dimg04.c-ctrip.com/images/0231n12000d6psmwzC0B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000d6p96cv851C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000d6p54g4DF1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000d6por8n31E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000d6pph9c080F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000d6pmgxkE3C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000d6pqyls78B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000d6pbyug0595_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000d6pplk5CACF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-12', '城央绿意双床房', '双床房', '家庭亲子', 21, 0, 20, 4, '["整体满意度","餐饮设施"]'::jsonb, '整体满意度', '餐饮设施', NULL),
('68028542e3c98b094176618d', '被白金五星给骗了，本来以为是贝聿铭设计的，想来体验一下。然后一进房间就是一股很浓的发霉味道。晚上发现原来一洗澡地板就会漏水。然后房间窗户是封闭式的，很本不通风，所以浓浓的霉味。特别不满意，住到现在最差的五星。', '["https://dimg04.c-ctrip.com/images/0202p12000cck321v2534_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236y12000cck1jdkF6D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 104, 0, 14, 8, '["房间设施","卫生状况","整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度'),
('68028542e3c98b094176618e', '太惊艳了，果然没有选错。白金级的服务超赞。除了酒店环境无可挑剔、后花园内的岭南景物让人难忘。入住时送了水果。打卡点后送了文创小物。哈哈哈??开心。', '["https://dimg04.c-ctrip.com/images/0233t12000cjb9j5gC35A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000cjb5nv136C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000cjb85eeEA16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000cjbb14006BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000cjbebxpDAAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000cjbe0tr964E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000cjbeu9dBE15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000cjbbycg6BE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000cjbgoesAC7F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-08', '红棉大床套房', '套房', '家庭亲子', 73, 0, 20, 8, '["前台服务","整体满意度","周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套'),
('68028542e3c98b094176618f', '粤韵双床房非常舒适，64平米，适合一家三口入住，晚上小朋友睡觉后还可以在客厅独立的空间看书或看剧。老牌五星酒店，房间隔断做得很好，隔音效果不错。另外，酒店餐厅也很值得打卡，荔湾亭性价比相对高。', '["https://dimg04.c-ctrip.com/images/0232b12000cazzlocAE89_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '粤韵双床套房', '套房', '家庭亲子', 96, 0, 7, 9, '["房间设施","安静程度","餐饮设施"]'::jsonb, '房间设施', '安静程度', '餐饮设施'),
('68028542e3c98b0941766190', '各方面都不错', '["https://dimg04.c-ctrip.com/images/0230w12000dd3pmtsCF1D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000dd41a25148D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000dd3xskhD038_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000dd3y7l929D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-07', '花园大床房', '大床房', '商务出差', 6, 0, 5, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b0941766191', '开了三间房，两间出问题。
第一间：
1.1房卡日期设置错误，无法开房门，下去前台，问我们是否续住的，最后前台解释说日期设置错，是上位前台开卡失误。
1.2入住登记时，已提出要求把三间作关联，因为前台为了快速处理入住，没有告知房卡分别用了谁的信息登记，导致重新开卡时的误会，第一次增加了与前台沟通成本，因为原接待的前台走开了。

第二间：
2.1门锁措施残旧未更换。刷卡进房，门锁显示灯为绿色，但扭动无效，喊了在隔壁的房务员，几次也开不了。
2.2服务响应速度慢。通过楼层电话直拨客服中心，如上反应情况，因为1.2中不知道房卡登记谁的信息，对方也不直接说我信息错误，来回间第二次增加了沟通成本，核对好信息，对方表示让礼宾的同事上来，耐心等待了十来分钟，再次拨打电话，对方表示已看到礼宾员上来找我们，再次耐心等待，才等来礼宾员。
2.3升级房间失误。礼宾员试过门后，主动提出升级房间，并为我们换房卡并带我们去新的房间，我们再再次耐心等待，结果新的房间是双人房，原来房间是大床。礼宾员电话叫房务员拿卡开隔壁房，然后我们再再再次耐心等待，房间没错了。
2.4突**况无备注。礼宾下去换卡给我们，我们婉言拒绝，因为原定外出的时间已耽误很久了，只能晚上我们自己去前台拿卡，让帮忙开好卡就行。晚上回来报了新房号给前台，前台一脸懵，但他并没有表明问题所在，又是一次次无效沟通，他也不停地点击鼠标，我们再再再再次耐心等待，最后我把入住到之前的说了，并主动说了三位入住信息，他才说“难怪和登记的不一样”，第三次增加沟通成本。然而新的房间根本没有为我们预留，也没有任何注明，好在没开出去，不然都不用睡了。
2.5基础专业失误。开好房卡后，前台主动提出带我们到房间，以防其他情况发生。结果房卡刷不开门，显示灯是红色。我们再再再再再次耐心等待前台重新开卡。
最后要赞一下的。唯一一间没有任何问题的，是我爸妈入住的，对大堂工作人员很满意，主动服务意识非常强，房间也很宽敞舒适，对第三次入住花园酒店，仍然是非常满意。真的很谢谢，再再再再再再次感谢', '["https://dimg04.c-ctrip.com/images/0231h12000c7cs670D9E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000c7d14wd4F35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000c7cx9m08E42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000c7d3aa326D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-09-21', '红棉大床套房', '套房', '家庭亲子', 858, 0, 4, 9, '["前台服务","退房/入住效率","客房服务"]'::jsonb, '前台服务', '退房/入住效率', '客房服务'),
('68028542e3c98b0941766192', '目前住过广州最有特色的酒店，整个酒店就像一间巨大的博物馆??就很有历史底蕴，酒店的外国友人也很多。本来以为这么老的酒店，只是住个特色，没想到真正住下来很惊喜。床品软硬适中，让人一躺下来就想睡觉。', '["https://dimg04.c-ctrip.com/images/0233f12000c7ruvp46DC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000c7s31fu2F57_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000c7s3kdwF242_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000c7rymqkAC63_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000c7s2s215E1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000c7s32emD380_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000c7s1jgtA717_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000c7s2geq14B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000c7rsy6y540B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-22', '红棉大床套房', '套房', '家庭亲子', 97, 0, 4, 8, '["整体满意度","房间设施"]'::jsonb, '整体满意度', '房间设施', NULL),
('68028542e3c98b0941766193', '首先我想说.一直出差来广州.住过很多家酒店.但是对于我这个挑剔的人来说.我很喜欢花园酒店.品牌有文化底蕴.尤其是吃早饭下午茶的瀑布酒店很漂亮.装修风格干净典雅.服务也很好.让你心里舒服.停车在隔壁的地下停车场也很方便.总之希望继续保持哦.以后只要来广州就是花园酒店！', '["https://dimg04.c-ctrip.com/images/0230e12000c5h2u95A728_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000c5grlf4CE05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000c5h4x3aA0E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000c5gtqasC300_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000c5gtqau9F82_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-15', '花园大床房', '大床房', '商务出差', 133, 0, 55, 8, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68028542e3c98b0941766194', '前台Katherine、Gtillian小姐姐服务态度非常不错，专门给她的好评。交通便利，停车方便!停车场很大，还是免费停车场。房间很大，设施也很齐全。房间还送的有矿泉水。前台小姐姐估计是考虑我要休养，给我升级了房型一房一厅高楼层真是太舒服了！床上用品洗的也很干净，床垫软软的，睡起来很舒服。中央空调很凉快。有什么需要，给前台打电话，都能解决!前台小姐姐还详细的讲解了吗无线网，早餐种类等!真的很好！', '["https://dimg04.c-ctrip.com/images/0231n12000c4hb8yn5177_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000c4hg3ez3316_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000c4he5ug2B02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '红棉大床套房', '套房', '其他', 200, 0, 5, 9, '["前台服务","交通便利性","房间设施"]'::jsonb, '前台服务', '交通便利性', '房间设施'),
('68028542e3c98b0941766195', '设施：一流和先进。
卫生：干净。
环境：优美、静谧。
服务：到位。大堂部服务员James Mancy的服务态度热情，主动帮我升级房型。客房部经理Echo主动关心我住的怎么样。
广州花园酒店真是好！还想再住一次。', '["https://dimg04.c-ctrip.com/images/0232412000fa9f49b0BFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000fa9l5ckC632_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000fa9wbv02FAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000fa9dtbfBE0E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-28', '花园双床房', '双床房', '家庭亲子', 105, 0, 39, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028542e3c98b0941766196', '很棒的酒店，下次来广州会首先考虑，花园非常漂亮', '["https://dimg04.c-ctrip.com/images/0235c12000cyhtfp1D3BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000cyht0s50C3E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000cyhtkrd2188_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '花园双床房', '双床房', '家庭亲子', 23, 0, 10, 5, '["整体满意度","景观/朝向"]'::jsonb, '整体满意度', '景观/朝向', NULL),
('68028542e3c98b0941766198', '住的很舒服，服务很好，房间干净，还给升级了房间', '["https://dimg04.c-ctrip.com/images/0235u12000cy3sgih6B9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000cy3vgvc5BE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000cy3rlf545E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000cy3wnfg5F58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000cy451uuCD3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000cy3eatp1F2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000cy47j8g6E5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000cy480r25945_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-16', '花园双床房', '双床房', '家庭亲子', 23, 0, 10, 6, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68028542e3c98b0941766199', '设施齐全园林景观很好', '["https://dimg04.c-ctrip.com/images/0234a12000df7ldbp049A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-15', '羊羊得意主题大床套房', '主题房', '家庭亲子', 10, 0, 6, 4, '["公共设施","景观/朝向"]'::jsonb, '公共设施', '景观/朝向', NULL),
('68028542e3c98b094176619a', '花园酒店，完完全全颠覆了我的感知，－个长达38年的白金五星级酒店保养的如此完美！醉了！！！
酒店的硬件不说，它的专业程度更让我敬佩，从前台，到锦鲤行政酒廊，再到自助餐厅，佩服佩服，这一切让我连住四晚，真真切切体验了并亨受着，在此感谢花园酒店，感谢花园酒店的员工，更要感谢Getting.和Getting.和Bettg谢谢你们了感受了你们专业，优秀，传承了花园酒店的优良传统，再次感谢，
并一同感谢酒店的客服，多次电话关怀，五星的好评必须要给你们！！！', '["https://dimg04.c-ctrip.com/images/0235p12000c2frp9eEEF8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000c2fm06yAF5F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-04', '花园大床房', '大床房', '家庭亲子', 225, 0, 15, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68028542e3c98b094176619b', '白金五星级的服务还是非常给力的，酒店重新装修后硬件也还可以，比新酒店的科技感会差一些，但胜在人文和服务上，酒店的卡通人物如果能十一期间赠送入住的小孩那就更完美了', '["https://dimg04.c-ctrip.com/images/0230e12000cby39vk01BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000cby0zlf8AB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000cby4q1f4742_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '红棉大床套房', '套房', '家庭亲子', 80, 0, 10, 7, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68028542e3c98b094176619c', '服务很好的酒店，带老人孩子一起来的，住的很舒服，第二天还给我们升级了一间房间，很开心的一次旅行，还有礼物拿，孩子很开心，谢谢前台小钟', '["https://dimg04.c-ctrip.com/images/0233n12000cyhssniD9F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000cyhs8nj2E57_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000cyhslj0DE3D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '花园大床房', '大床房', '家庭亲子', 66, 0, 10, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b094176619d', '房间非常好，服务非常周到大堂的话非常干净景色还是非常漂亮的后花园也非常漂亮。特别感谢前台Kasas和betty', '["https://dimg04.c-ctrip.com/images/0237212000jdj2p3o9F85_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-28', '花园大床房', '大床房', '朋友出游', 55, 0, 3, 6, '["前台服务","房间设施","卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况'),
('68028542e3c98b094176619e', '满意，服务属于住过的酒店中一流的。虽然设施比较老旧了，但是干净的。', '["https://dimg04.c-ctrip.com/images/0236812000cwxh0fgA2F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000cwx87fl4331_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000cwx1dmc52A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-11', '花园大床房', '大床房', '情侣出游', 33, 0, 6, 6, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68028542e3c98b094176619f', '酒店地理位置优越 出行方便 出门就是地铁??', '["https://dimg04.c-ctrip.com/images/0231j12000cvrtj0q88F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000cvroaq8A8D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000cvrm9evA3B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000cvrrgwbBC78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000cvrovx59AE8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000cvrrj3p8A00_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000cvruzhv95E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000cvroaqcA3ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-07', '花园双床房', '双床房', '其他', 22, 0, 3, 4, '["交通便利性","周边配套"]'::jsonb, '交通便利性', '周边配套', NULL),
('68028542e3c98b09417661a0', '不得不说 酒店的服务是可以打满分的 每一次出来旅行总会多少有一些小插曲 那也不影响我对花园酒店的好感  带父母和小朋友出来 选择花园没错了', '["https://dimg04.c-ctrip.com/images/0231h12000cbkx9p04A60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000cbl0whrAF73_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000cbksd6u5224_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '红棉大床套房', '套房', '家庭亲子', 69, 0, 6, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b09417661a1', '酒店有一定的历史，桃园馆菜品精致美味，行政酒廊外籍人员Carrie，ken服务很贴心。下次假期会带娃一起过来体验，感恩遇见', '["https://dimg04.c-ctrip.com/images/0232f12000csaseev57A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000csavbq86DA8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-23', '粤韵双床套房', '套房', '朋友出游', 61, 0, 6, 7, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68028542e3c98b09417661a2', '每样都很好，吃的餐廳有六家选择，还有酒廊听歌。????
设施：很多很好。
卫生：有自动喷雾机，很香。
环境：很多拍照的打卡位，大堂常换景。
服务：打扫的阿姨很贴心。', '["https://dimg04.c-ctrip.com/images/0232q12000c5i0rz1B1B2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-16', '花园大床房', '大床房', '情侣出游', 82, 0, 33, 7, '["餐饮设施","卫生状况","客房服务"]'::jsonb, '餐饮设施', '卫生状况', '客房服务'),
('68028542e3c98b09417661a3', '老牌的就是不一样 一如十多年前的样子，前台接待很显气派', '["https://dimg04.c-ctrip.com/images/0234h12000cx4xp7w1DB5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000cx4wbo1C3A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000cx4vrp7518B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-01-12', '花园大床房', '大床房', '商务出差', 27, 0, 87, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b09417661a4', '设施：还好，至少没有不舒适

卫生：挺干净的

环境：周围环境还不错
服务：态度很好，至少笑脸很多
下次再去住试试看，挺好的??????????', '["https://dimg04.c-ctrip.com/images/0232h12000cd1ve1cEBD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236d12000cd1wwsz336D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000cd1ygjr102A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '花园大床房', '大床房', '情侣出游', 72, 0, 5, 5, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028542e3c98b09417661a5', '环境真的非常好，有山有水又很安静，房间也非常好，刚从广州的花园酒店离开来到这里，房间面积，设师，卫生，服务都不比花园酒店差，值得来', '["https://dimg04.c-ctrip.com/images/0236a12000cc4uajq70E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000cc4ubuy244A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000cc4ubw57449_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 65, 0, 3, 8, '["整体满意度","安静程度","卫生状况"]'::jsonb, '整体满意度', '安静程度', '卫生状况'),
('68028542e3c98b09417661a6', '酒店的环境不错，但是修路他们不安排里面的房间也不提醒你有这样的情况， 太吵了', '["https://dimg04.c-ctrip.com/images/023563234d9x3otio3E65_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2, 2, '2023-11-20', '粤韵大床套房', '套房', '其他', 38, 0, 27, 6, '["安静程度","前台服务"]'::jsonb, '安静程度', '前台服务', NULL),
('68028542e3c98b09417661a7', '广州花园酒店，是我在全国住过众多酒店，唯一一个还想下次来入住的酒店，虽然酒店已经有30年的历史，但酒店整体从环境到服务，没有一个地方让人挑出毛病的，服务非常体贴入微，下次来广州一定还会选择花园酒店，酒店环境真的很美！', '["https://dimg04.c-ctrip.com/images/0236j12000bw8k7hc6EE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000bw8r9hi3B79_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000bw8h30b0AB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000bw8lxqg5D63_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-12', '花园大床房', '大床房', '商务出差', 108, 0, 30, 8, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68028542e3c98b09417661a8', '虽然酒店历史悠久，但整体环境、装潢一点也不陈旧。工作人员都很热情，特别是泳池边的几位工作人员，一直贴身守护着小孩子，点个大大的??', '["https://dimg04.c-ctrip.com/images/0234712000cbopqzh35D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000cbopi86F466_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000cboq53p239A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 65, 0, 4, 7, '["公共设施","前台服务","整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度'),
('68028542e3c98b09417661a9', '方便很干净.很舒服.这个大床说的我好开心.本来打算住一晚体验下.换别的酒店.结果连着自己了好几天目前还在酒店住.停车也很方便.是免费的.整体来说环境好.舒服方便.', '["https://dimg04.c-ctrip.com/images/0235j12000c30xrrj927B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000c30n9vi1B61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000c30sgd0E055_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000c30r6vyBA5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000c31077qB586_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-07', '花园大床房', '大床房', '商务出差', 81, 0, 55, 6, '["整体满意度","卫生状况","公共设施"]'::jsonb, '整体满意度', '卫生状况', '公共设施'),
('68028542e3c98b09417661aa', '很棒的住宿体验，服务很好，谢谢前台小钟送的礼物', '["https://dimg04.c-ctrip.com/images/0232x12000cyhtfsp50B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000cyhtqua33BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-17', '花园双床房', '双床房', '家庭亲子', 23, 0, 10, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b09417661ab', '酒店很大很漂亮，食店都已有六间，服务也很好，环境与空气都很好，我俩很满意。??????????', '["https://dimg04.c-ctrip.com/images/0234l12000c4v8n8s1EBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000c4valk0AB3F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000c4vao3qAA1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000c4vbvjm1A03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000c4vaef38DF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000c4va66eCCC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000c4vbpgp3112_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000c4vanjy0209_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000c4v8dcjAF4C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-14', '花园大床房', '大床房', '情侣出游', 47, 0, 33, 5, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68028542e3c98b09417661ac', '一家很有故事的酒店
设施：各类设施齐全
卫生：地毯清洁到位
环境：花园里几乎没有蚊子，可见下了功夫
服务：服务人员训练有素
